const fs = require('fs')
const path = require('path')

const repoRoot = path.resolve(__dirname, '..')
const claudePath = path.join(repoRoot, 'CLAUDE.md')
const agentsPath = path.join(repoRoot, 'AGENTS.md')

const source = fs.readFileSync(claudePath, 'utf8')

const normalized = source.replace(/^#\s+CLAUDE\.md\s*$/m, '# AGENTS.md')

const generated = [
  '# AGENTS.md',
  '',
  '> This file is auto-generated from `CLAUDE.md`.',
  '> Do not edit this file directly. Run `npm run sync:agents` instead.',
  '',
  normalized.replace(/^#\s+AGENTS\.md\s*\n?/m, '').trimStart(),
  '',
].join('\n')

fs.writeFileSync(agentsPath, generated, 'utf8')

console.log(`Generated ${path.relative(repoRoot, agentsPath)} from CLAUDE.md`)
